2186 static Instruction *foldSubOfMinMax(BinaryOperator &I,
2187                                     InstCombiner::BuilderTy &Builder) {
2188   Value *Op0 = I.getOperand(0);
2189   Value *Op1 = I.getOperand(1);
2190   Type *Ty = I.getType();
2191   auto *MinMax = dyn_cast<MinMaxIntrinsic>(Op1);
2192   if (!MinMax)
2193     return nullptr;
2194 
2195   // sub(add(X,Y), s/umin(X,Y)) --> s/umax(X,Y)
2196   // sub(add(X,Y), s/umax(X,Y)) --> s/umin(X,Y)
2197   Value *X = MinMax->getLHS();
2198   Value *Y = MinMax->getRHS();
2199   if (match(Op0, m_c_Add(m_Specific(X), m_Specific(Y))) &&
2200       (Op0->hasOneUse() || Op1->hasOneUse())) {
2201     Intrinsic::ID InvID = getInverseMinMaxIntrinsic(MinMax->getIntrinsicID());
2202     Function *F = Intrinsic::getOrInsertDeclaration(I.getModule(), InvID, Ty);
2203     return CallInst::Create(F, {X, Y});
2204   }
2205 
2206   // sub(add(X,Y),umin(Y,Z)) --> add(X,usub.sat(Y,Z))
2207   // sub(add(X,Z),umin(Y,Z)) --> add(X,usub.sat(Z,Y))
2208   Value *Z;
2209   if (match(Op1, m_OneUse(m_UMin(m_Value(Y), m_Value(Z))))) {
2210     if (match(Op0, m_OneUse(m_c_Add(m_Specific(Y), m_Value(X))))) {
2211       Value *USub = Builder.CreateIntrinsic(Intrinsic::usub_sat, Ty, {Y, Z});
2212       return BinaryOperator::CreateAdd(X, USub);
2213     }
2214     if (match(Op0, m_OneUse(m_c_Add(m_Specific(Z), m_Value(X))))) {
2215       Value *USub = Builder.CreateIntrinsic(Intrinsic::usub_sat, Ty, {Z, Y});
2216       return BinaryOperator::CreateAdd(X, USub);
2217     }
2218   }
2219 
2220   // sub Op0, smin((sub nsw Op0, Z), 0) --> smax Op0, Z
2221   // sub Op0, smax((sub nsw Op0, Z), 0) --> smin Op0, Z
2222   if (MinMax->isSigned() && match(Y, m_ZeroInt()) &&
2223       match(X, m_NSWSub(m_Specific(Op0), m_Value(Z)))) {
2224     Intrinsic::ID InvID = getInverseMinMaxIntrinsic(MinMax->getIntrinsicID());
2225     Function *F = Intrinsic::getOrInsertDeclaration(I.getModule(), InvID, Ty);
2226     return CallInst::Create(F, {Op0, Z});
2227   }
2228 
2229   return nullptr;
2230 }
